$files = @('apps','packages','scripts','.github','vercel.json','turbo.json','.env.example')
$lines = rg "process\.env\.|^[A-Z][A-Z0-9_]*=" @files -g "*.ts" -g "*.tsx" -g "*.json" -g "*.yml" -g "*.yaml" -g "*.example"
$vars = New-Object System.Collections.Generic.HashSet[string]
foreach ($line in $lines) {
  foreach ($m in [regex]::Matches($line, 'process\.env\.([A-Z][A-Z0-9_]*)')) { [void]$vars.Add($m.Groups[1].Value) }
  foreach ($m in [regex]::Matches($line, '^.*?:([A-Z][A-Z0-9_]*)=')) { [void]$vars.Add($m.Groups[1].Value) }
  foreach ($m in [regex]::Matches($line, '"([A-Z][A-Z0-9_]*)"')) { if ($line -match 'turbo.json') { [void]$vars.Add($m.Groups[1].Value) } }
}
$docs = Get-Content AGENTS.md,docs\configuration.md,.env.example,turbo.json -Raw
$vars | Sort-Object | Where-Object { $docs -notmatch [regex]::Escape($_) }
